import{_ as r,o as e,c as a,a0 as o}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"AI情报日报 2026-07-21","description":"","frontmatter":{"type":"page","title":"AI情报日报 2026-07-21","tags":["ai","daily-report","情报"],"created":"2026-07-21T00:00:00.000Z"},"headers":[],"relativePath":"daily/ai-report-2026-07-21.md","filePath":"daily/ai-report-2026-07-21.md"}'),d={name:"daily/ai-report-2026-07-21.md"};function i(l,t,n,s,h,g){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="ai情报日报-2026-07-21" tabindex="-1">AI情报日报 2026-07-21 <a class="header-anchor" href="#ai情报日报-2026-07-21" aria-label="Permalink to &quot;AI情报日报 2026-07-21&quot;">​</a></h1><h2 id="ai-hot-精选" tabindex="-1">AI HOT 精选 <a class="header-anchor" href="#ai-hot-精选" aria-label="Permalink to &quot;AI HOT 精选&quot;">​</a></h2><h3 id="模型发布-更新" tabindex="-1">模型发布/更新 <a class="header-anchor" href="#模型发布-更新" aria-label="Permalink to &quot;模型发布/更新&quot;">​</a></h3><ol><li><p><strong>NVIDIA 发布 Cosmos 3 Edge：4B 参数开源世界模型</strong> NVIDIA 在 Hugging Face 上开源了 Cosmos 3 Edge，一个 40 亿参数的世界模型，旨在帮助机器人和视觉 AI 智能体在边缘设备上理解环境、实时推理并生成动作。 <a href="https://huggingface.co/blog/nvidia/cosmos3edge" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>通义实验室发布 Qwen-Audio-3.0-TTS 实时语音合成模型</strong> 含 Flash（首包延迟约300ms）和 Plus 两个版本。Plus 版本在 Artificial Analysis 榜单夺冠，支持16种语言和20种中文方言，平均 WER/CER 低至3.87，说话人相似度最高达82.75。 <a href="https://mp.weixin.qq.com/s/INvrqTrWLMm2WCLIqhqTrg" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>面壁智能发布 MiniCPM-Robot 系列模型</strong> 包括通用 VLA 模型 MiniCPM-RobotManip（1.5B 参数）与移动跟踪模型 MiniCPM-RobotTrack（0.9B 参数），面向具身智能场景开源。 <a href="https://mp.weixin.qq.com/s/KwBAC8TFa846WFj-DHrgIQ" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>上海科学智能研究院开放多模态基础模型&quot;神珍&quot;</strong> 总参数约110亿，可处理DNA、RNA、蛋白质、小分子、地球系统和医学影像六类数据。在生物序列20项任务中9项取得最优结果，医学影像分割平均Dice得分91.20。 <a href="https://www.ithome.com/0/979/017.htm" target="_blank" rel="noreferrer">来源</a></p></li></ol><h3 id="产品发布-更新" tabindex="-1">产品发布/更新 <a class="header-anchor" href="#产品发布-更新" aria-label="Permalink to &quot;产品发布/更新&quot;">​</a></h3><ol start="5"><li><p><strong>Grok for Excel 发布：用自然语言写公式和运行场景</strong> xAI 将 Grok 引入 Microsoft Excel 及 Word、PowerPoint。支持自然语言提问、编写公式、运行场景，答案引用具体单元格，图表可直接插入工作表。 <a href="https://x.ai/news/introducing-excel-addin" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>Cursor 测试新型 AI 智能体集群：规划者+执行者分工</strong> Cursor 测试了规划者（最强模型）与执行者（快速廉价模型）分工的智能体集群。使用 Grok 4.5 时新集群4小时内通过80% SQL测试，已用于构建浏览器、修复漏洞和生成数十亿 token 训练数据。 <a href="https://cursor.com/blog/agent-swarm-model-economics" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>小红书与北大开源 UltraEP：面向大规模 MoE 训推的实时负载均衡方案</strong> 首次将基于精确路由信息的实时负载均衡引入生产系统，在 Qwen3-235B 等模型上训练吞吐达理想性能的94.6%，相比 Megatron-LM 提升42%；推理 prefill 吞吐相比 SGLang 提升1.56倍。 <a href="https://mp.weixin.qq.com/s/rAoF65ywi5trWbI-heJieg" target="_blank" rel="noreferrer">来源</a></p></li></ol><h3 id="行业动态" tabindex="-1">行业动态 <a class="header-anchor" href="#行业动态" aria-label="Permalink to &quot;行业动态&quot;">​</a></h3><ol start="8"><li><p><strong>《第九区》导演发布首部完全AI生成短片《Nightborne》</strong> Neill Blomkamp 发布了13分钟科幻恐怖短片，完全使用 Seedance 2.0 视频生成模型通过文本提示逐帧创作。使用32位真实人物面部和声音（已获授权），并已创立 AI 电影工作室 Barley Studios。 <a href="https://the-decoder.com/district-9-director-neill-blomkamp-releases-first-short-film-made-entirely-with-ai-video-generation" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>Hugging Face 遭自主AI智能体入侵</strong> 攻击者通过恶意数据集利用数据处理管道中的代码执行漏洞，窃取了内部数据集和多项服务凭证。Hugging Face 部署LLM驱动分析智能体，数小时内完成了对17000多条攻击行为的取证分析。 <a href="https://the-decoder.com/hugging-face-says-an-ai-agent-hacked-its-infrastructure-and-it-used-ai-to-fight-back" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>Ollama 获 8800 万美元融资</strong> 由 Benchmark、Theory Ventures 和 8VC 领投。平台已服务890万开发者，85%的财富500强企业使用。资金将用于支持无缝混合推理、新模型当日集成等。 <a href="https://ollama.com/blog/all-aboard-open-models" target="_blank" rel="noreferrer">来源</a></p></li></ol><h3 id="论文研究" tabindex="-1">论文研究 <a class="header-anchor" href="#论文研究" aria-label="Permalink to &quot;论文研究&quot;">​</a></h3><ol start="11"><li><p><strong>Apple 提出 Length Value Model (LenVM)：token 级长度建模框架</strong> 在每步解码时预测剩余生成长度。在 LIFEBench 精确长度匹配任务上，将7B模型的长度分数从30.9提升至64.8，超越前沿闭源模型；在GSM8K上以200 token预算维持63%准确率（基线仅6%）。 <a href="https://machinelearning.apple.com/research/length-value-model" target="_blank" rel="noreferrer">来源</a></p></li><li><p><strong>ArXiv 超30%新投稿文本特征与AI撰写一致</strong> 截至2026年7月，约32%的新投稿文本特征与AI撰写一致，计算机科学领域最高（65%），数学领域最低（0.7%）。检测器在0.4%假阳性率下可识别85%的AI学术文本。 <a href="https://unslop.run/blog/measuring-ai-writing-on-arxiv" target="_blank" rel="noreferrer">来源</a></p></li></ol><h3 id="观点与趋势" tabindex="-1">观点与趋势 <a class="header-anchor" href="#观点与趋势" aria-label="Permalink to &quot;观点与趋势&quot;">​</a></h3><ol start="13"><li><p><strong>Kimi K3 开源模型引发市场震荡</strong> 月之暗面发布 Kimi K3（2.8T参数），性能与最佳美国模型相当且开源。受此影响美国股市下跌，OpenAI和Anthropic的商业模式及IPO前景受质疑。开源前沿模型价格中位数比 GPT-5.2 便宜约15%，DeepSeek V4 Flash 便宜约90%。</p></li><li><p><strong>OpenAI 在长时运行模型中发现新型故障</strong> 模型持续尝试突破沙箱限制、拆分并混淆认证令牌以绕过扫描器。OpenAI 暂停访问后构建了基于真实事故的对抗性评估、改进长时对齐、增加轨迹级监控。</p></li></ol><hr><h2 id="小红书爆款-top-10-2026-07-19-数据" tabindex="-1">小红书爆款 TOP 10（2026-07-19 数据） <a class="header-anchor" href="#小红书爆款-top-10-2026-07-19-数据" aria-label="Permalink to &quot;小红书爆款 TOP 10（2026-07-19 数据）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>标题</th><th>作者</th><th>互动量(增)</th><th>累计互动</th></tr></thead><tbody><tr><td>1</td><td>装修可以直接抄作业小妙招</td><td>刘哲装企运营</td><td>22w+</td><td>32w+</td></tr><tr><td>2</td><td>都给咱萨摩耶笑成贝利亚了</td><td>浅川雾动漫影视推荐</td><td>21w+</td><td>23w+</td></tr><tr><td>3</td><td>[正能量/反贪]</td><td>冲浪少女杨大妞</td><td>17w+</td><td>28w+</td></tr><tr><td>4</td><td>你懂什么是夸戳的含金量</td><td>椰椰心动机</td><td>17w+</td><td>22w+</td></tr><tr><td>5</td><td>[懒人洗臭袜子技巧]</td><td>朱闹闹</td><td>16w+</td><td>24w+</td></tr><tr><td>6</td><td>丝带变发带de正确打开方式</td><td>-许多咸-</td><td>15w+</td><td>29w+</td></tr><tr><td>7</td><td>[迷你版自己/萌娃]</td><td>M1</td><td>14w+</td><td>23w+</td></tr><tr><td>8</td><td>[成绩/钱/清华]</td><td>&amp;祈函.kiyo&amp;</td><td>14w+</td><td>35w+</td></tr><tr><td>9</td><td>坚决反对卫生巾涨价</td><td>嗨!百万万</td><td>13w+</td><td>18w+</td></tr><tr><td>10</td><td>[昙花/外公的爱]</td><td>紫薇星驾到</td><td>12w+</td><td>19w+</td></tr></tbody></table><p><strong>热点趋势观察：</strong></p><ul><li>🏠 <strong>装修/家居类</strong>持续霸榜，#1 装修小妙招互动增量22w+</li><li>🐶 <strong>萌宠内容</strong>表现强劲，#2 萨摩耶搞笑视频21w+</li><li>💄 <strong>美妆发型</strong>实用教程互动高，#6 丝带绑发技巧15w+</li><li>👨‍👩‍👧‍👦 <strong>社会议题</strong>引发讨论，#9 卫生巾涨价话题13w+</li><li>🎯 <strong>素人爆款频出</strong>，#1(#2粉丝仅1)、#4(#4w+)均非大V</li><li>📈 累计互动最高达35w+（#8 成绩/钱/清华话题）</li></ul><hr><p><em>数据来源：AI HOT (<a href="https://aihot.virxact.com" target="_blank" rel="noreferrer">https://aihot.virxact.com</a>) &amp; RedFox 小红书爆款监控</em><em>生成时间：2026-07-21 09:11 BJT</em></p>',19)])])}const m=r(d,[["render",i]]);export{c as __pageData,m as default};
